// WIP-mode service worker unregister shim.
// This file is served at /sw.js when WIP mode is on, replacing
// the PWA service worker that aggressively cached old HTML. The
// install step unregisters itself and clears all caches, ensuring
// users see the latest content. In production (WIP off), the
// real PWA service worker generated by next-pwa is served.

self.addEventListener("install", (event) => {
  self.skipWaiting();
});

self.addEventListener("activate", (event) => {
  event.waitUntil(
    (async () => {
      // Delete all caches created by the previous PWA SW
      if ("caches" in self) {
        const keys = await caches.keys();
        await Promise.all(keys.map((key) => caches.delete(key)));
      }
      // Unregister this no-op SW
      await self.registration.unregister();
      // Force all open clients to reload so they fetch fresh HTML
      const clients = await self.clients.matchAll({ type: "window" });
      for (const client of clients) {
        client.navigate(client.url);
      }
    })(),
  );
});

// Pass-through fetch — don't intercept anything
self.addEventListener("fetch", (event) => {
  return;
});
